import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
  type PropsWithChildren
} from 'react';
import { db } from '../db/db';
import type { NavMode, User, UserRole } from '../types';

interface AuthContextValue {
  currentUser: User | null;
  navMode: NavMode;
  login: (username: string, password: string) => Promise<void>;
  logout: () => void;
  hasRole: (...roles: UserRole[]) => boolean;
  encryptionKey: CryptoKey | null;
}

const AuthContext = createContext<AuthContextValue | undefined>(undefined);

function encodeHex(bytes: Uint8Array): string {
  return [...bytes].map((byte) => byte.toString(16).padStart(2, '0')).join('');
}

async function sha256(value: string): Promise<string> {
  const digest = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(value));
  return encodeHex(new Uint8Array(digest));
}

function deriveNavMode(user: User | null): NavMode {
  if (!user) {
    return 'kiosk';
  }

  return user.role === 'Attendant' || user.role === 'SiteManager' ? 'kiosk' : 'admin';
}

export function AuthProvider({ children }: PropsWithChildren) {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [encryptionKey] = useState<CryptoKey | null>(null);

  const login = useCallback(async (username: string, password: string) => {
    const user = await db.users.where('username').equals(username).first();

    if (!user) {
      throw new Error('Invalid username or password');
    }

    const hash = await sha256(password);
    if (hash !== user.passwordHash) {
      throw new Error('Invalid username or password');
    }

    setCurrentUser(user);
  }, []);

  const logout = useCallback(() => {
    setCurrentUser(null);
  }, []);

  const hasRole = useCallback(
    (...roles: UserRole[]) => {
      if (!currentUser) {
        return false;
      }

      return roles.includes(currentUser.role);
    },
    [currentUser]
  );

  const value = useMemo<AuthContextValue>(
    () => ({
      currentUser,
      navMode: deriveNavMode(currentUser),
      login,
      logout,
      hasRole,
      encryptionKey
    }),
    [currentUser, encryptionKey, hasRole, login, logout]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }

  return context;
}

