import { Suspense, lazy, type ReactNode } from 'react';
import { Navigate, Outlet, Route, Routes } from 'react-router-dom';
import AdminShell from '../components/Layout/AdminShell';
import KioskShell from '../components/Layout/KioskShell';
import { useAuth } from '../hooks/useAuth';
import type { UserRole } from '../types';

const AdminDashboardPage = lazy(() => import('../pages/AdminDashboardPage'));
const AuditLogPage = lazy(() => import('../pages/AuditLogPage'));
const DataQualityPage = lazy(() => import('../pages/DataQualityPage'));
const ForbiddenPage = lazy(() => import('../pages/ForbiddenPage'));
const ImportPage = lazy(() => import('../pages/ImportPage'));
const KioskDashboardPage = lazy(() => import('../pages/KioskDashboardPage'));
const LoginPage = lazy(() => import('../pages/LoginPage'));
const NotificationsPage = lazy(() => import('../pages/NotificationsPage'));
const ReservationsPage = lazy(() => import('../pages/ReservationsPage'));
const SessionsOrdersPage = lazy(() => import('../pages/SessionsOrdersPage'));
const SiteConfigPage = lazy(() => import('../pages/SiteConfigPage'));
const UserManagementPage = lazy(() => import('../pages/UserManagementPage'));

interface ProtectedRouteProps {
  allowedRoles?: UserRole[];
  children?: ReactNode;
}

function ProtectedRoute({ allowedRoles, children }: ProtectedRouteProps) {
  const { currentUser, hasRole } = useAuth();

  if (!currentUser) {
    return <Navigate to="/login" replace />;
  }

  if (allowedRoles && !hasRole(...allowedRoles)) {
    return <ForbiddenPage />;
  }

  return <>{children ?? <Outlet />}</>;
}

export function AppRouter() {
  return (
    <Suspense fallback={<div className="page-loading">Loading...</div>}>
      <Routes>
        <Route path="/" element={<Navigate to="/login" replace />} />
        <Route path="/login" element={<LoginPage />} />

        <Route
          path="/kiosk"
          element={
            <ProtectedRoute allowedRoles={['Attendant', 'SiteManager']}>
              <KioskShell />
            </ProtectedRoute>
          }
        >
          <Route index element={<KioskDashboardPage />} />
          <Route
            path="reservations"
            element={
              <ProtectedRoute allowedRoles={['Attendant', 'SiteManager']}>
                <ReservationsPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="sessions"
            element={
              <ProtectedRoute allowedRoles={['Attendant', 'SiteManager']}>
                <SessionsOrdersPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="notifications"
            element={
              <ProtectedRoute allowedRoles={['Attendant', 'SiteManager']}>
                <NotificationsPage />
              </ProtectedRoute>
            }
          />
        </Route>

        <Route
          path="/admin"
          element={
            <ProtectedRoute>
              <AdminShell />
            </ProtectedRoute>
          }
        >
          <Route index element={<Navigate to="/admin/dashboard" replace />} />
          <Route
            path="dashboard"
            element={
              <ProtectedRoute allowedRoles={['SystemAdministrator', 'Auditor']}>
                <AdminDashboardPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="reservations"
            element={
              <ProtectedRoute allowedRoles={['SystemAdministrator']}>
                <ReservationsPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="sessions"
            element={
              <ProtectedRoute allowedRoles={['SystemAdministrator', 'Auditor']}>
                <SessionsOrdersPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="import"
            element={
              <ProtectedRoute allowedRoles={['SystemAdministrator', 'SiteManager']}>
                <ImportPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="quality"
            element={
              <ProtectedRoute allowedRoles={['SystemAdministrator', 'Auditor']}>
                <DataQualityPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="audit"
            element={
              <ProtectedRoute allowedRoles={['SystemAdministrator', 'Auditor']}>
                <AuditLogPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="config"
            element={
              <ProtectedRoute allowedRoles={['SystemAdministrator', 'SiteManager']}>
                <SiteConfigPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="notifications"
            element={
              <ProtectedRoute
                allowedRoles={['SystemAdministrator', 'SiteManager', 'Attendant', 'Auditor']}
              >
                <NotificationsPage />
              </ProtectedRoute>
            }
          />
          <Route
            path="users"
            element={
              <ProtectedRoute allowedRoles={['SystemAdministrator']}>
                <UserManagementPage />
              </ProtectedRoute>
            }
          />
        </Route>

        <Route path="*" element={<Navigate to="/login" replace />} />
      </Routes>
    </Suspense>
  );
}

