import { FormEvent, useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

export default function LoginPage() {
  const { currentUser, login, navMode } = useAuth();
  const navigate = useNavigate();

  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!currentUser) {
      return;
    }

    navigate(navMode === 'kiosk' ? '/kiosk' : '/admin/dashboard', { replace: true });
  }, [currentUser, navigate, navMode]);

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setError(null);

    try {
      await login(username.trim(), password);
    } catch (submitError) {
      const message = submitError instanceof Error ? submitError.message : 'Login failed';
      setError(message);
    }
  };

  return (
    <section className="login-page">
      <form className="card login-card" onSubmit={handleSubmit}>
        <h1>ChargeBay Offline Operations Console</h1>
        <p>Sign in with your local account.</p>

        <label htmlFor="username">Username</label>
        <input
          id="username"
          name="username"
          value={username}
          onChange={(event) => setUsername(event.target.value)}
          autoComplete="username"
          required
        />

        <label htmlFor="password">Password</label>
        <input
          id="password"
          name="password"
          type="password"
          value={password}
          onChange={(event) => setPassword(event.target.value)}
          autoComplete="current-password"
          required
        />

        {error ? <p className="error">{error}</p> : null}

        <button className="button primary" type="submit">
          Login
        </button>
      </form>
    </section>
  );
}

