files.before:
:root {
  --bg: #f2f4f8;
  --surface: #ffffff;
  --text: #132035;
  --muted: #5a6780;
  --brand: #0e7490;
  --brand-strong: #155e75;
  --border: #d4dbe7;
  --danger: #b42318;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background: radial-gradient(circle at top left, #e9f5fb 0%, var(--bg) 55%);
  color: var(--text);
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
}

a {
  color: inherit;
  text-decoration: none;
}

.page-loading {
  min-height: 100vh;
  display: grid;
  place-items: center;
}

.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 1.2rem;
  box-shadow: 0 8px 22px rgba(16, 26, 44, 0.06);
}

.login-page {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 1rem;
}

.login-card {
  width: min(430px, 100%);
  display: grid;
  gap: 0.7rem;
}

label {
  font-size: 0.9rem;
  font-weight: 600;
}

input {
  width: 100%;
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.65rem 0.8rem;
  font-size: 0.95rem;
}

.error {
  color: var(--danger);
  margin: 0;
}

.button {
  border: 1px solid transparent;
  border-radius: 10px;
  padding: 0.55rem 0.9rem;
  font-weight: 600;
  cursor: pointer;
}

.button.primary {
  background: linear-gradient(135deg, var(--brand), var(--brand-strong));
  color: #fff;
}

.button.ghost {
  background: transparent;
  border-color: var(--border);
}

.kiosk-shell,
.admin-shell {
  min-height: 100vh;
}

.shell-topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.7rem;
  padding: 0.8rem 1rem;
  background: #fff;
  border-bottom: 1px solid var(--border);
}

.shell-main {
  padding: 1rem;
}

.kiosk-tabs {
  position: sticky;
  bottom: 0;
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  border-top: 1px solid var(--border);
  background: #fff;
}

.kiosk-tabs a {
  padding: 0.9rem 0.5rem;
  text-align: center;
  color: var(--muted);
  font-weight: 600;
}

.kiosk-tabs a.active {
  color: var(--brand-strong);
}

.admin-shell {
  display: grid;
  grid-template-columns: 250px 1fr;
}

.admin-content {
  min-width: 0;
}

.admin-header-left {
  display: flex;
  align-items: center;
  gap: 0.6rem;
}

.sidebar {
  padding: 1rem;
  border-right: 1px solid var(--border);
  background: #f8fafc;
}

.sidebar-title {
  margin-top: 0;
}

.sidebar-links {
  display: grid;
  gap: 0.4rem;
}

.sidebar-link {
  padding: 0.55rem 0.7rem;
  border-radius: 9px;
  color: var(--muted);
}

.sidebar-link.active {
  background: #dff0f7;
  color: var(--brand-strong);
}

.badge {
  border-radius: 999px;
  padding: 0.2rem 0.55rem;
  font-size: 0.8rem;
  background: #eef2f6;
}

.table {
  width: 100%;
  border-collapse: collapse;
}

.table th,
.table td {
  border-bottom: 1px solid var(--border);
  padding: 0.65rem;
  text-align: left;
}

.overlay {
  position: fixed;
  inset: 0;
  background: rgba(7, 17, 31, 0.35);
  display: grid;
  place-items: center;
}

.modal {
  width: min(560px, 95vw);
  background: #fff;
  border-radius: 12px;
  padding: 1rem;
}

.modal-header,
.drawer-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.drawer {
  position: fixed;
  top: 0;
  right: -400px;
  width: min(380px, 95vw);
  height: 100vh;
  transition: right 0.25s ease;
  background: #fff;
  border-left: 1px solid var(--border);
  padding: 1rem;
}

.drawer.open {
  right: 0;
}

.toast {
  border-radius: 10px;
  padding: 0.7rem 0.9rem;
  background: #dff0f7;
}

@media (max-width: 900px) {
  .admin-shell {
    grid-template-columns: 1fr;
  }

  .sidebar {
    border-right: none;
    border-bottom: 1px solid var(--border);
  }
}

