+import { cryptoService } from '../services/cryptoService';
@@
-function encodeHex(bytes: Uint8Array): string {
-  return [...bytes].map((byte) => byte.toString(16).padStart(2, '0')).join('');
-}
-
-async function sha256(value: string): Promise<string> {
-  const digest = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(value));
-  return encodeHex(new Uint8Array(digest));
-}
-
 async function seedUsers() {
   const users: User[] = [];

   for (const user of DEMO_USERS) {
+    const { hash, salt } = await cryptoService.hashPassword(user.password);
     users.push({
       username: user.username,
-      passwordHash: await sha256(user.password),
-      salt: '',
+      passwordHash: hash,
+      salt,
       role: user.role,
       siteId: user.siteId,
       failedAttempts: 0
@@
   await db.bays.bulkAdd(bays);
 }
+
+async function migrateLegacySeedUsers() {
+  const users = await db.users.toArray();
+  const demoPasswordByUsername = new Map(DEMO_USERS.map((entry) => [entry.username, entry.password]));
+
+  for (const user of users) {
+    if (user.salt) {
+      continue;
+    }
+
+    const password = demoPasswordByUsername.get(user.username);
+    if (!password || !user.id) {
+      continue;
+    }
+
+    const { hash, salt } = await cryptoService.hashPassword(password);
+    await db.users.update(user.id, { passwordHash: hash, salt, failedAttempts: 0, lockedUntil: undefined });
+  }
+}

 export async function seedIfEmpty() {
   const userCount = await db.users.count();
   if (userCount > 0) {
+    await migrateLegacySeedUsers();
     return;
   }
*** End Patch"}

