const DEMO_USERS: Array<{ username: string; password: string; role: UserRole; siteId?: number }> = [
  { username: 'sysadmin', password: 'ChargeBay#Admin1', role: 'SystemAdministrator' },
  { username: 'manager', password: 'ChargeBay#Mgr01', role: 'SiteManager', siteId: 1 },
  { username: 'attendant', password: 'ChargeBay#Att01', role: 'Attendant', siteId: 1 },
  { username: 'auditor', password: 'ChargeBay#Aud01', role: 'Auditor', siteId: 1 }
];

function encodeHex(bytes: Uint8Array): string {
  return [...bytes].map((byte) => byte.toString(16).padStart(2, '0')).join('');
}

async function sha256(value: string): Promise<string> {
  const digest = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(value));
  return encodeHex(new Uint8Array(digest));
}

async function seedUsers() {
  const users: User[] = [];

  for (const user of DEMO_USERS) {
    users.push({
      username: user.username,
      passwordHash: await sha256(user.password),
      salt: '',
      role: user.role,
      siteId: user.siteId,
      failedAttempts: 0
    });
  }

  await db.users.bulkAdd(users);
}

async function seedSiteAndBays() {
  const site: Site = { siteCode: 'SITE-001', name: 'ChargeBay Site 1' };
  const siteId = await db.sites.add(site);

  const bays: Bay[] = ['ST-01', 'ST-02', 'ST-03', 'ST-04'].map((stationId, index) => ({
    siteId,
    stationId,
    connectorId: 'C1',
    label: `Bay ${index + 1}`,
    status: 'Available'
  }));

  await db.bays.bulkAdd(bays);
}

export async function seedIfEmpty() {
  const userCount = await db.users.count();
  if (userCount > 0) {
    return;
  }

  await db.transaction('rw', db.users, db.sites, db.bays, async () => {
    await seedSiteAndBays();
    await seedUsers();
  });
}

