import { db } from '../db/db';
import type { Order, User } from '../types';
import { auditService } from './auditService';
import { cryptoService } from './cryptoService';
import { assertSiteScope } from './rbacService';

type OrderCreateInput = Omit<Order, 'id' | 'version' | 'invoiceNotes'> & {
  invoiceNotes?: string;
};

async function createOrder(actor: User, input: OrderCreateInput, encryptionKey: CryptoKey): Promise<number> {
  assertSiteScope(actor, input.siteId);
  const encryptedNotes = input.invoiceNotes
    ? await cryptoService.encryptField(input.invoiceNotes, encryptionKey)
    : undefined;

  const orderId = await db.orders.add({
    ...input,
    invoiceNotes: encryptedNotes,
    version: 1
  });
  await auditService.log(actor, 'ORDER_CREATED', 'Order', orderId, {
    orderNumber: input.orderNumber,
    siteId: input.siteId
  });
  return orderId;
}

async function getOrder(actor: User, orderId: number, encryptionKey: CryptoKey): Promise<Order | null> {
  const order = await db.orders.get(orderId);
  if (!order) {
    return null;
  }

  assertSiteScope(actor, order.siteId);

  return {
    ...order,
    invoiceNotes: order.invoiceNotes
      ? await cryptoService.decryptField(order.invoiceNotes, encryptionKey)
      : undefined
  };
}

export const orderService = {
  createOrder,
