+interface ReservationQrPayload {
+  reservationId: number;
+  operationId: string;
+  siteCode: string;
+}
+
+function encodePayload(payload: ReservationQrPayload): string {
+  return JSON.stringify(payload);
+}
+
+function parsePayload(qrPayload: string): ReservationQrPayload {
+  return JSON.parse(qrPayload) as ReservationQrPayload;
+}
+
+function toDataUrl(payload: string): string {
+  if (typeof document === 'undefined') {
+    return `data:text/plain;base64,${btoa(payload)}`;
+  }
+
+  const canvas = document.createElement('canvas');
+  canvas.width = 220;
+  canvas.height = 220;
+  const context = canvas.getContext('2d');
+  if (!context) {
+    return `data:text/plain;base64,${btoa(payload)}`;
+  }
+
+  context.fillStyle = '#ffffff';
+  context.fillRect(0, 0, 220, 220);
+  context.fillStyle = '#111827';
+  context.font = '12px monospace';
+  context.fillText('ChargeBay QR', 16, 30);
+  const chunks = payload.match(/.{1,24}/g) ?? [payload];
+  chunks.slice(0, 10).forEach((line, index) => {
+    context.fillText(line, 16, 55 + index * 14);
+  });
+
+  return canvas.toDataURL('image/png');
+}
+
+export const qrService = {
+  encodePayload,
+  parsePayload,
+  toDataUrl
+};
+
*** End Patch"}

