import { db } from '../db/db';
import type { Reservation, User } from '../types';
import { auditService } from './auditService';
import { cryptoService } from './cryptoService';
import { assertSiteScope } from './rbacService';

type ReservationCreateInput = Omit<Reservation, 'id' | 'version' | 'customerName' | 'customerPlate'> & {
  customerName: string;
  customerPlate: string;
};

async function createReservation(
  actor: User,
  input: ReservationCreateInput,
  encryptionKey: CryptoKey
): Promise<number> {
  assertSiteScope(actor, input.siteId);

  const encryptedName = await cryptoService.encryptField(input.customerName, encryptionKey);
  const encryptedPlate = await cryptoService.encryptField(input.customerPlate, encryptionKey);

  const reservationId = await db.reservations.add({
    ...input,
    customerName: encryptedName,
    customerPlate: encryptedPlate,
    version: 1
  });

  await auditService.log(actor, 'RESERVATION_CREATED', 'Reservation', reservationId, {
    siteId: input.siteId,
    bayId: input.bayId,
    operationId: input.operationId
  });

  return reservationId;
}

async function getReservationsBySite(actor: User, siteId: number): Promise<Reservation[]> {
  assertSiteScope(actor, siteId);
  return db.reservations.where('siteId').equals(siteId).toArray();
}

async function getDecryptedReservation(
  actor: User,
  reservationId: number,
  encryptionKey: CryptoKey
): Promise<Reservation | null> {
  const reservation = await db.reservations.get(reservationId);
  if (!reservation) {
    return null;
  }

  assertSiteScope(actor, reservation.siteId);
  return {
    ...reservation,
    customerName: await cryptoService.decryptField(reservation.customerName, encryptionKey),
    customerPlate: await cryptoService.decryptField(reservation.customerPlate, encryptionKey)
  };
}

export const reservationService = {
  createReservation,
  getReservationsBySite,
  getDecryptedReservation
};

