import { useEffect } from 'react';
import { BrowserRouter } from 'react-router-dom';
import { AuthProvider, useAuth } from './hooks/useAuth';
import { heartbeatService } from './services/heartbeatService';
import { reservationService } from './services/reservationService';
import { AppRouter } from './router';

function Scheduler() {
  const { currentUser } = useAuth();

  useEffect(() => {
    if (!currentUser) {
      return;
    }

    const heartbeatTimer = window.setInterval(() => {
      void heartbeatService.tick(currentUser);
    }, 30_000);

    const anomalyTimer = window.setInterval(() => {
      void heartbeatService.checkAnomalies(currentUser);
    }, 60_000);

    const noShowTimer = window.setInterval(() => {
      void reservationService.autoProcessNoShows(currentUser);
    }, 60_000);

    return () => {
      window.clearInterval(heartbeatTimer);
      window.clearInterval(anomalyTimer);
      window.clearInterval(noShowTimer);
    };
  }, [currentUser]);

  return null;
}

function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Scheduler />
        <AppRouter />
      </BrowserRouter>
    </AuthProvider>
  );
}

export default App;

