:root {
  --bg: #f2f4f8;
  --surface: #ffffff;
  --text: #132035;
  --muted: #5a6780;
  --brand: #0e7490;
  --brand-strong: #155e75;
  --border: #d4dbe7;
  --danger: #b42318;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background: radial-gradient(circle at top left, #e9f5fb 0%, var(--bg) 55%);
  color: var(--text);
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
}

a {
  color: inherit;
  text-decoration: none;
}

.page-loading {
  min-height: 100vh;
  display: grid;
  place-items: center;
}

.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 1.2rem;
  box-shadow: 0 8px 22px rgba(16, 26, 44, 0.06);
}

.login-page {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 1rem;
}

.login-card {
  width: min(430px, 100%);
  display: grid;
  gap: 0.7rem;
}

label {
  font-size: 0.9rem;
  font-weight: 600;
}

input {
  width: 100%;
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.65rem 0.8rem;
  font-size: 0.95rem;
}

select {
  width: 100%;
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.65rem 0.8rem;
  font-size: 0.95rem;
  background: #fff;
}

.error {
  color: var(--danger);
  margin: 0;
}

.button {
  border: 1px solid transparent;
  border-radius: 10px;
  padding: 0.55rem 0.9rem;
  font-weight: 600;
  cursor: pointer;
}

.button.primary {
  background: linear-gradient(135deg, var(--brand), var(--brand-strong));
  color: #fff;
}

.button.ghost {
  background: transparent;
  border-color: var(--border);
}

.kiosk-shell,
.admin-shell {
  min-height: 100vh;
}

.shell-topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.7rem;
  padding: 0.8rem 1rem;
  background: #fff;
  border-bottom: 1px solid var(--border);
}

.shell-main {
  padding: 1rem;
}

