}

.admin-content {
  min-width: 0;
}

.admin-header-left {
  display: flex;
  align-items: center;
  gap: 0.6rem;
}

.sidebar {
  padding: 1rem;
  border-right: 1px solid var(--border);
  background: #f8fafc;
}

.sidebar-title {
  margin-top: 0;
}

.sidebar-links {
  display: grid;
  gap: 0.4rem;
}

.sidebar-link {
  padding: 0.55rem 0.7rem;
  border-radius: 9px;
  color: var(--muted);
}

.sidebar-link.active {
  background: #dff0f7;
  color: var(--brand-strong);
}

.badge {
  border-radius: 999px;
  padding: 0.2rem 0.55rem;
  font-size: 0.8rem;
  background: #eef2f6;
}

.table {
  width: 100%;
  border-collapse: collapse;
}

.table th,
.table td {
  border-bottom: 1px solid var(--border);
  padding: 0.65rem;
  text-align: left;
}

.overlay {
  position: fixed;
  inset: 0;
  background: rgba(7, 17, 31, 0.35);
  display: grid;
  place-items: center;
}

.modal {
  width: min(560px, 95vw);
  background: #fff;
  border-radius: 12px;
  padding: 1rem;
}

.modal-header,
.drawer-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.drawer {
  position: fixed;
  top: 0;
  right: -400px;
  width: min(380px, 95vw);
  height: 100vh;
  transition: right 0.25s ease;
  background: #fff;
  border-left: 1px solid var(--border);
  padding: 1rem;
}

.drawer.open {
  right: 0;
}

.toast {
  border-radius: 10px;
  padding: 0.7rem 0.9rem;
  background: #dff0f7;
}

.user-actions {
  display: grid;
  gap: 0.4rem;
}

.create-user-form {
  display: grid;
  gap: 0.6rem;
  margin-top: 0.6rem;
}

.page-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.75rem;
}

.bay-grid {
  margin-top: 1rem;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 0.8rem;
}

.bay-card {
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.8rem;
  background: #fff;
}

.drawer-actions {
  display: grid;
  gap: 0.5rem;
  margin: 0.8rem 0;
}

.qr-preview {
  width: 180px;
