    status: 'Refunded',
    adjustmentReason: reason,
    version: order.version + 1
  });
  await auditService.log(actor, 'ORDER_REFUNDED', 'Order', orderId, { reason });
}

async function setReconciliationStatus(
  orderId: number,
  status: 'Matched' | 'Discrepancy',
