import { db } from '../db/db';
import type { User } from '../types';
import { auditService } from './auditService';

async function sendTemplateToSiteStaff(siteId: number, templateKey: string, actor?: User): Promise<void> {
  const recipients = await db.users.where('siteId').equals(siteId).toArray();
  const now = Date.now();
  const rows = recipients
    .filter((user) => user.role === 'Attendant' || user.role === 'SiteManager')
    .map((user) => ({
      recipientId: user.id as number,
      templateKey,
      status: 'Queued' as const,
      isRead: false,
      createdAt: now,
      retries: 0
    }));

  if (rows.length > 0) {
    await db.notifications.bulkAdd(rows);
  }

  if (actor) {
    await auditService.log(actor, 'NOTIFICATION_QUEUED', 'Notification', templateKey, {
      recipients: rows.length
    });
  }
}

export const notificationService = {
  sendTemplateToSiteStaff
};

