      {tab === 'Inbox' ? (
        <>
          <div className="tab-row">
            {(['All', 'Unread', 'Archived'] as Filter[]).map((name) => (
              <button
                key={name}
                className={`button ${filter === name ? 'primary' : 'ghost'}`}
