                        Archive
                      </button>
                    </td>
                  </tr>
                  {expandedId === row.id ? (
                    <tr>
                      <td colSpan={6}>
                        <div className="notif-body">{row.renderedBody}</div>
                      </td>
                    </tr>
                  ) : null}
                </Fragment>
              ))}
            </tbody>
          </table>
        </>
      ) : null}

      {tab === 'SendLog' && canViewSendLog ? (
        <table className="table">
          <thead>
            <tr>
              <th>Recipient</th>
              <th>Template</th>
