import { useEffect, useState } from 'react';
import { BrowserRouter } from 'react-router-dom';
import { AuthProvider, useAuth } from './hooks/useAuth';
import { heartbeatService } from './services/heartbeatService';
import { notificationService } from './services/notificationService';
import { qualityService } from './services/qualityService';
import { reservationService } from './services/reservationService';
import { AppRouter } from './router';

function Runtime() {
  const { currentUser } = useAuth();
  const [banner, setBanner] = useState<string | null>(null);

  useEffect(() => {
    if (!currentUser) {
      return;
    }

    const siteId = currentUser.siteId;
    if (siteId) {
      const qualityLastRunKey = `cb_quality_lastRun_${siteId}`;
      const lastRun = Number(localStorage.getItem(qualityLastRunKey) ?? 0);
      const now = Date.now();
      if (now - lastRun > 7 * 24 * 60 * 60 * 1000) {
        void qualityService.runReport(siteId, currentUser).then(() => {
          localStorage.setItem(qualityLastRunKey, String(now));
        });
      }
    }

    const heartbeatTimer = window.setInterval(() => {
      void heartbeatService.tick(currentUser);
    }, 30_000);

    const anomalyTimer = window.setInterval(() => {
      void heartbeatService.checkAnomalies(currentUser);
    }, 60_000);

    const noShowTimer = window.setInterval(() => {
      void reservationService.autoProcessNoShows(currentUser);
    }, 60_000);

    const notifRetryTimer = window.setInterval(() => {
      void notificationService.retryFailed();
    }, 30_000);

    const notifRuleTimer = window.setInterval(() => {
      void notificationService.runDueAndOverdueSchedulers(currentUser);
    }, 60_000);

    const clearBanner = window.setInterval(() => setBanner(null), 5_000);
    notificationService.setBannerListener((subject, userId) => {
      if (currentUser.id === userId) {
        setBanner(subject);
      }
    });

    return () => {
      window.clearInterval(heartbeatTimer);
      window.clearInterval(anomalyTimer);
      window.clearInterval(noShowTimer);
      window.clearInterval(notifRetryTimer);
      window.clearInterval(notifRuleTimer);
      window.clearInterval(clearBanner);
      notificationService.setBannerListener(null);
    };
  }, [currentUser]);

  if (!banner) {
    return null;
  }

  return <div className="notif-banner">{banner}</div>;
}

function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Runtime />
        <AppRouter />
      </BrowserRouter>
    </AuthProvider>
  );
}

export default App;

