async function runWeeklyIfDue(siteId: number, actor: User): Promise<boolean> {
  const key = `cb_quality_lastRun_${siteId}`;
  const now = Date.now();
  const lastRun = Number(localStorage.getItem(key) ?? 0);
  if (now - lastRun <= 7 * 24 * 60 * 60 * 1000) {
