export type ImportType = 'reservations' | 'orders' | 'sessions';
export type FieldMap = Record<string, string>;

const REQUIRED_FIELDS: Record<ImportType, string[]> = {
  reservations: [
    'stationId',
    'connectorId',
    'customerName',
    'customerPlate',
    'scheduledStart',
    'scheduledEnd'
  ],
  orders: [
    'orderNumber',
    'sessionId',
    'durationMinutes',
    'ratePerMinute',
    'adjustmentAmount',
    'adjustmentReason',
    'invoiceNotes'
  ],
  sessions: ['reservationId', 'startedAt']
};

const TEMPLATE_ROWS: Record<ImportType, { headers: string[]; sample: string[] }> = {
  reservations: {
    headers: [
      'stationId',
      'connectorId',
      'customerName',
      'customerPlate',
      'scheduledStart',
      'scheduledEnd'
    ],
    sample: ['ST-01', 'C1', 'Alex Doe', 'ABC123', '04/01/2026 09:30', '04/01/2026 11:00']
  },
  orders: {
    headers: [
      'orderNumber',
      'sessionId',
      'durationMinutes',
      'ratePerMinute',
      'adjustmentAmount',
      'adjustmentReason',
      'invoiceNotes'
    ],
    sample: ['CB-SITE-001-20260401-0001', '100', '90', '0.5', '0', '', 'Imported invoice note']
  },
  sessions: {
    headers: ['reservationId', 'startedAt'],
    sample: ['100', '04/01/2026 09:30']
  }
};

function parseCsv(csv: string): { headers: string[]; rows: Record<string, string>[] } {
  const lines = csv
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean);
  if (lines.length === 0) {
    return { headers: [], rows: [] };
  }
  const headers = lines[0].split(',').map((entry) => entry.trim());
  const rows = lines.slice(1).map((line) => {
    const cells = line.split(',');
    const row: Record<string, string> = {};
    headers.forEach((header, index) => {
      row[header] = (cells[index] ?? '').trim();
    });
    return row;
  });

  return { headers, rows };
}

function parseDate(value: string): number | null {
  const match = value.match(/^(\d{2})\/(\d{2})\/(\d{4})\s(\d{2}):(\d{2})$/);
  if (!match) {
    return null;
  }
  const [, mm, dd, yyyy, hh, min] = match;
  const date = new Date(Number(yyyy), Number(mm) - 1, Number(dd), Number(hh), Number(min));
  if (Number.isNaN(date.getTime())) {
    return null;
  }
  return date.getTime();
}

async function sha256(text: string): Promise<string> {
  const buffer = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(text));
  return [...new Uint8Array(buffer)].map((b) => b.toString(16).padStart(2, '0')).join('');
}

async function parseFile(file: File): Promise<{ headers: string[]; rows: Record<string, string>[]; raw: string }> {
  if (file.name.toLowerCase().endsWith('.xlsx')) {
