      'scheduledStart',
      'scheduledEnd'
    ],
    sample: ['ST-01', 'C1', 'Alex Doe', 'ABC123', '04/01/2026 09:30', '04/01/2026 11:00']
  },
  orders: {
    headers: [
      'orderNumber',
      'sessionId',
      'durationMinutes',
      'ratePerMinute',
      'adjustmentAmount',
      'adjustmentReason',
