      scheduledStart: Date.now(),
      scheduledEnd: Date.now() + 60_000,
      status: 'Scheduled',
      qrCode: '{}'
    })),
    confirmArrival,
    startTempLeave: vi.fn(),
    endTempLeave: vi.fn()
  },
  TempLeaveLimitError: class TempLeaveLimitError extends Error {}
}));

