import { expect, test } from '@playwright/test';

test('create reservation and manual check-in', async ({ page }) => {
  await page.goto('/login');
  await page.fill('#username', 'attendant');
  await page.fill('#password', 'ChargeBay#Att01');
  await page.getByRole('button', { name: 'Login' }).click();
  await page.goto('/kiosk/reservations');

  await page.getByRole('button', { name: 'New Reservation' }).click();
  await page.locator('form.modal select').first().selectOption({ index: 1 });
  await page.getByPlaceholder('Customer Name').fill('E2E User');
  await page.getByPlaceholder('Customer Plate').fill('E2E123');
  const now = new Date(Date.now() + 30 * 60_000);
  const later = new Date(Date.now() + 90 * 60_000);
  const toInput = (d: Date) => `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(
    d.getDate()
  ).padStart(2, '0')}T${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`;
  await page.locator('input[type="datetime-local"]').nth(0).fill(toInput(now));
  await page.locator('input[type="datetime-local"]').nth(1).fill(toInput(later));
  await page.getByRole('button', { name: 'Save Reservation' }).click();
  await expect(page.getByText('Check In').first()).toBeVisible();

  await page.getByText('Check In').first().click();
  await page.getByRole('button', { name: 'Confirm Arrival' }).click();
  await expect(page.getByText('Arrival confirmed manually.')).toBeVisible();
});

