import { expect, test } from '@playwright/test';

test('import valid and invalid csv', async ({ page }) => {
  await page.goto('/login');
  await page.fill('#username', 'sysadmin');
  await page.fill('#password', 'ChargeBay#Admin1');
  await page.getByRole('button', { name: 'Login' }).click();
  await page.goto('/admin/import');

  const valid = [
    'stationId,connectorId,customerName,customerPlate,scheduledStart,scheduledEnd',
    'ST-01,C1,Import User,IMP123,04/01/2027 09:30,04/01/2027 11:00'
  ].join('\n');
  await page.setInputFiles('input[type="file"]', {
    name: 'valid.csv',
    mimeType: 'text/csv',
    buffer: Buffer.from(valid)
  });
  await page.getByRole('button', { name: 'Validate' }).click();
  await expect(page.getByText(/rows found/i)).toBeVisible();

  const invalid = [
    'stationId,connectorId,customerName,customerPlate,scheduledStart,scheduledEnd',
    'ST-01,C1,Import User,IMP123,BAD_DATE,04/01/2027 11:00'
  ].join('\n');
  await page.setInputFiles('input[type="file"]', {
    name: 'invalid.csv',
    mimeType: 'text/csv',
    buffer: Buffer.from(invalid)
  });
  await page.getByRole('button', { name: 'Validate' }).click();
  await expect(page.getByText(/IMPORT_DATE_FORMAT_INVALID/i)).toBeVisible();
});

